INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00814', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '若新臺幣兌美元的匯率由三十比一變為三十三比一。在其他條件不變下，此一匯率的變化，在國際貿易 上顯示出下列何種意義？', '["進口物品的價格下降", "鼓勵民眾去美國旅遊", "新臺幣貶值刺激出口", "出口業者的損失提高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00815', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '當人工智慧系統AlphaGo戰勝人類九段圍棋高手的那一刻，全人類開始惶惑。有專家預言本世紀末，70% 的職業會被自動化技術取代，將有50%的白領智慧工作者會失業。下列何者最能解決上述的失業問題？', '["採行緊縮性的貨幣政策", "提供就業資訊", "提供符合市場需求的職業訓練", "推動擴張性財政政策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00816', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '某家超商鼓勵民眾將200元的統一發票中獎金額存在會員卡中，再加碼贈送50點會員點數，讓民眾可以 把它當現金 5 元使用，藉此吸引更多的來客率。在其他條件不變的情況下，上述超商考量的目的應為下 列何者？', '["降低生產的成本", "增加銷貨的收入", "減少生產者剩餘", "提升生產要素的需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00817', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '酒駕問題造成無數家破人亡，成為眾所矚目的社會問題，因此政府乃修改「道路交通管理處罰條例」， 提高對酒駕的行政上處罰，希望藉此遏止酒駕行為。下列敘述何者正確？', '["這是以政府的法律管制處理市場失靈問題", "針對酒駕提高的行政上處罰是一種行政指導", "此一處罰可以增加中央政府租稅方面的收入", "若民眾對此一處罰不服可以向法院提出抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00818', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '許多國家都由政府制訂法律，規定雇主給付給勞工的最低薪資，目的是保障工人能以勞力換取足以維持 生存的工資。從經濟學的角度來分析，在其他條件不變的情形下，此種政策可能會對勞動市場造成下列 何項影響？', '["造成勞動市場供過於求的現象，而使失業率提升", "勞工的工作意願減少，進而導致勞動供給會減少", "廠商能夠僱用到更多勞工，因此勞動需求會增加", "使勞動市場供需雙方都獲利，整體社會福祉增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00819', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '歐盟是區域整合的國際組織，關於此組織的敘述，下列何者錯誤？', '["經濟上對外採取單一關稅", "過半數的會員國採取共同貨幣", "重經濟整合，缺少司法與政治上合作", "申請加入需具備保障人權與市場經濟條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00820', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '假設天龍國近來財政赤字增加，若該國政府欲增加其收入，以縮小財政赤字，下列何種作法可以達成目的？', '["收取菸品的健康捐", "降低遺產稅的稅率", "縮減社會福利支出", "增加公共建設經費"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00821', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '根據行政院主計總處統計，中央、地方政府等公務人事費用每年編列經費逾新臺幣一兆元，約占中央政 府歲出預算的六成。若以政府支出項目來看，此人事費用支出應為下列何者？', '["投資支出", "債務利息支出", "移轉性支出", "消費支出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00822', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '近年來東南亞國協逐漸受到重視，該組織也致力促進區域合作與創造和平。關於東南亞國協的敘述，下 列何者正確？', '["我國以「中華臺北」名義加入", "該組織為聯合國下的週邊組織", "目標為建立政治經濟文化共同體", "俗稱東協加一是指日本的加入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00823', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '某家酒商過去將葡萄酒製程的廢料紅麴當作肥料，現在則改製成厚度僅0.3公分的紅麴餅乾，為該公司賺 進七億元的商機。上述作法突顯何項生產要素的重要性？', '["人力資源", "人造資本", "自然資源", "企業才能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:42+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
